    suspend fun processInAppPurchase(
        productId: String,
        price: Double,
        currency: String,
        paymentMethod: PaymentMethod
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val transaction = Transaction(
                    id = generateTransactionId(),
                    productId = productId,
                    amount = price,
                    currency = currency,
                    timestamp = System.currentTimeMillis(),
                    status = TransactionStatus.PENDING
                )

                transactionManager.saveTransaction(transaction)

                when (paymentMethod) {
                    is PaymentMethod.CreditCard -> processCreditCardPayment(transaction, paymentMethod)
                    is PaymentMethod.Wallet -> processWalletPayment(transaction, paymentMethod)
                    is PaymentMethod.GooglePay -> processGooglePayPayment(transaction)
                }
            } catch (e: Exception) {
                Log.e("PaymentModule", "Payment processing failed", e)
                PaymentResult.Error(e.message ?: "Unknown error")
            }
        }
    }

    private suspend fun processCreditCardPayment(
        transaction: Transaction,
        paymentMethod: PaymentMethod.CreditCard
    ): PaymentResult {
        val encryptedCardData = secureStorage.encryptCardData(
            cardNumber = paymentMethod.cardNumber,
            cvv = paymentMethod.cvv,
            expiryDate = paymentMethod.expiryDate
        )

        val paymentRequest = createPaymentRequest(transaction, encryptedCardData)
        val response = sendPaymentToGateway(paymentRequest)

        return if (response.success) {
            transaction.status = TransactionStatus.COMPLETED
            transactionManager.updateTransaction(transaction)
            PaymentResult.Success(transaction.id, response.receiptData)
        } else {
            transaction.status = TransactionStatus.FAILED
            transactionManager.updateTransaction(transaction)
            PaymentResult.Error(response.errorMessage ?: "Payment failed")
        }
    }

    private suspend fun processWalletPayment(
        transaction: Transaction,
        paymentMethod: PaymentMethod.Wallet
    ): PaymentResult {
        val wallet = transactionManager.getWalletBalance(paymentMethod.walletId)

        if (wallet.balance < transaction.amount) {
            transaction.status = TransactionStatus.FAILED
            transactionManager.updateTransaction(transaction)
            return PaymentResult.Error("Insufficient wallet balance")
        }

        val newBalance = wallet.balance - transaction.amount
        transactionManager.updateWalletBalance(paymentMethod.walletId, newBalance)

        transaction.status = TransactionStatus.COMPLETED
        transactionManager.updateTransaction(transaction)

        return PaymentResult.Success(transaction.id, "Wallet payment successful")
    }

